17: import { Room } from "matrix-js-sdk/src/models/room";
18: import { Thread, ThreadEvent } from "matrix-js-sdk/src/models/thread";
19: 
20: import { IDestroyable } from "../../utils/IDestroyable";
21: import { NotificationState, NotificationStateEvents } from "./NotificationState";
22: import { ThreadNotificationState } from "./ThreadNotificationState";
23: import { NotificationColor } from "./NotificationColor";
24: 
25: export class ThreadsRoomNotificationState extends NotificationState implements IDestroyable {
26:     public readonly threadsState = new Map<Thread, ThreadNotificationState>();
27: 
28:     protected _symbol = null;
29:     protected _count = 0;
30:     protected _color = NotificationColor.None;
31: 
32:     constructor(public readonly room: Room) {
33:         super();
34:         for (const thread of this.room.getThreads()) {
35:             this.onNewThread(thread);
36:         }
37:         this.room.on(ThreadEvent.New, this.onNewThread);
38:     }
39: 
40:     public destroy(): void {
41:         super.destroy();
42:         this.room.off(ThreadEvent.New, this.onNewThread);
43:         for (const [, notificationState] of this.threadsState) {
44:             notificationState.off(NotificationStateEvents.Update, this.onThreadUpdate);
45:         }
46:     }
47: 
48:     public getThreadRoomState(thread: Thread): ThreadNotificationState {
49:         if (!this.threadsState.has(thread)) {
50:             this.threadsState.set(thread, new ThreadNotificationState(thread));
51:         }
52:         return this.threadsState.get(thread);
53:     }
54: 
55:     private onNewThread = (thread: Thread): void => {
56:         const notificationState = new ThreadNotificationState(thread);
57:         this.threadsState.set(thread, notificationState);
58:         notificationState.on(NotificationStateEvents.Update, this.onThreadUpdate);
59:     };
60: 
61:     private onThreadUpdate = (): void => {
62:         let color = NotificationColor.None;
63:         for (const [, notificationState] of this.threadsState) {
64:             if (notificationState.color === NotificationColor.Red) {
65:                 color = NotificationColor.Red;
66:                 break;
67:             } else if (notificationState.color === NotificationColor.Grey) {
68:                 color = NotificationColor.Grey;
69:             }
70:         }
71:         this.updateNotificationState(color);
72:     };
73: 
74:     private updateNotificationState(color: NotificationColor): void {
75:         const snapshot = this.snapshot();
76:         this._color = color;
77:         // finally, publish an update if needed
78:         this.emitIfUpdated(snapshot);
79:     }
80: }
