17: import { MatrixEvent } from "matrix-js-sdk/src/models/event";
18: import { Thread, ThreadEvent } from "matrix-js-sdk/src/models/thread";
19: 
20: import { NotificationColor } from "./NotificationColor";
21: import { IDestroyable } from "../../utils/IDestroyable";
22: import { MatrixClientPeg } from "../../MatrixClientPeg";
23: import { NotificationState } from "./NotificationState";
24: 
25: export class ThreadNotificationState extends NotificationState implements IDestroyable {
26:     protected _symbol = null;
27:     protected _count = 0;
28:     protected _color = NotificationColor.None;
29: 
30:     constructor(public readonly thread: Thread) {
31:         super();
32:         this.thread.on(ThreadEvent.NewReply, this.handleNewThreadReply);
33:         this.thread.on(ThreadEvent.ViewThread, this.resetThreadNotification);
34:         if (this.thread.replyToEvent) {
35:             // Process the current tip event
36:             this.handleNewThreadReply(this.thread, this.thread.replyToEvent);
37:         }
38:     }
39: 
40:     public destroy(): void {
41:         super.destroy();
42:         this.thread.off(ThreadEvent.NewReply, this.handleNewThreadReply);
43:         this.thread.off(ThreadEvent.ViewThread, this.resetThreadNotification);
44:     }
45: 
46:     private handleNewThreadReply = (thread: Thread, event: MatrixEvent) => {
47:         const client = MatrixClientPeg.get();
48: 
49:         const myUserId = client.getUserId();
50: 
51:         const isOwn = myUserId === event.getSender();
52:         const readReceipt = this.thread.room.getReadReceiptForUserId(myUserId);
53: 
54:         if ((!isOwn && !readReceipt) || (readReceipt && event.getTs() >= readReceipt.data.ts)) {
55:             const actions = client.getPushActionsForEvent(event, true);
56: 
57:             if (actions?.tweaks) {
58:                 const color = !!actions.tweaks.highlight ? NotificationColor.Red : NotificationColor.Grey;
59: 
60:                 this.updateNotificationState(color);
61:             }
62:         }
63:     };
64: 
65:     private resetThreadNotification = (): void => {
66:         this.updateNotificationState(NotificationColor.None);
67:     };
68: 
69:     private updateNotificationState(color: NotificationColor) {
