function timelineHasUnread(timeline: MatrixEvent[], readUpToId: string | null, myUserId: string): boolean {
    // If the last event in the timeline was sent by the current user, don't mark as unread
    if (timeline.length && timeline[timeline.length - 1].getSender() === myUserId) {
        return false;
    }

    // Loop through messages, starting with the most recent...
    for (let i = timeline.length - 1; i >= 0; --i) {
        const ev = timeline[i];

        if (ev.getId() == readUpToId) {
            // If we've read up to this event, there's nothing more recent
            // that counts and we can stop looking because the user's read
            // this and everything before.
            return false;
        } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
            // We've found a message that counts, so this timeline is unread.
            return true;
        }
    }
    // If we got here, we didn't find a message that counted but didn't find
    // the user's read receipt either, so we guess and say that this timeline is
    // unread on the theory that false positives are better than false
    // negatives here.
    return readUpToId === null;
}

export function doesRoomHaveUnreadMessages(room: Room): boolean {
    if (SettingsStore.getValue("feature_sliding_sync")) {
        // TODO: https://github.com/vector-im/element-web/issues/23207
        // Sliding Sync doesn't support unread indicator dots (yet...)
        return false;
    }

    const myUserId = MatrixClientPeg.get().getUserId();

    // get the most recent read receipt sent by our account for the main timeline.
    // N.B. this is NOT a read marker (RM, aka "read up to marker"),
    // despite the name of the method :(
    const readUpToId = room.getEventReadUpTo(myUserId);

    // Check if the main timeline has unread messages
    if (timelineHasUnread(room.timeline, readUpToId, myUserId)) {
        return true;
    }

    // Check threads if the thread feature is enabled
    if (SettingsStore.getValue("feature_thread")) {
        for (const thread of room.getThreads()) {
            // Get the read receipt that applies to this thread
            const threadReadReceipt = thread.room.getReadReceiptForUserId(myUserId);
            const threadReadUpToId = threadReadReceipt?.data.event_id ?? null;

            // Check if this thread has unread messages
            if (timelineHasUnread(thread.timeline, threadReadUpToId, myUserId)) {
                return true;
            }
        }
    }

    return false;
}

