    25→import SettingsStore from "./settings/SettingsStore";
    26→
    27→/**
    28→ * Returns true if this event arriving in a room should affect the room's
    29→ * count of unread messages
    30→ *
    31→ * @param {Object} ev The event
    32→ * @returns {boolean} True if the given event should affect the unread message count
    33→ */
    34→export function eventTriggersUnreadCount(ev: MatrixEvent): boolean {
    35→    if (ev.getSender() === MatrixClientPeg.get().credentials.userId) {
    36→        return false;
    37→    }
    38→
    39→    switch (ev.getType()) {
    40→        case EventType.RoomMember:
    41→        case EventType.RoomThirdPartyInvite:
    42→        case EventType.CallAnswer:
    43→        case EventType.CallHangup:
    44→        case EventType.RoomCanonicalAlias:
    45→        case EventType.RoomServerAcl:
    46→        case M_BEACON.name:
    47→        case M_BEACON.altName:
    48→            return false;
    49→    }
    50→
    51→    if (ev.isRedacted()) return false;
    52→    return haveRendererForEvent(ev, false /* hidden messages should never trigger unread counts anyways */);
    53→}
    54→
    55→function timelineHasUnread(timeline: MatrixEvent[], readUpToId: string | null, myUserId: string): boolean {
    56→    // If the last event in the timeline was sent by the current user, don't mark as unread
    57→    if (timeline.length && timeline[timeline.length - 1].getSender() === myUserId) {
    58→        return false;
    59→    }
    60→
    61→    // Loop through messages, starting with the most recent...
    62→    for (let i = timeline.length - 1; i >= 0; --i) {
    63→        const ev = timeline[i];
    64→
    65→        if (ev.getId() == readUpToId) {
    66→            // If we've read up to this event, there's nothing more recent
    67→            // that counts and we can stop looking because the user's read
    68→            // this and everything before.
    69→            return false;
    70→        } else if (!shouldHideEvent(ev) && eventTriggersUnreadCount(ev)) {
    71→            // We've found a message that counts, so this timeline is unread.
    72→            return true;
    73→        }
    74→    }
    75→    // If we got here, we didn't find a message that counted but didn't find
    76→    // the user's read receipt either, so we guess and say that this timeline is
    77→    // unread on the theory that false positives are better than false
    78→    // negatives here.
    79→    return readUpToId === null;
    80→}
    81→
    82→export function doesRoomHaveUnreadMessages(room: Room): boolean {
    83→    if (SettingsStore.getValue("feature_sliding_sync")) {
    84→        // TODO: https://github.com/vector-im/element-web/issues/23207
    85→        // Sliding Sync doesn't support unread indicator dots (yet...)
    86→        return false;
    87→    }
    88→
    89→    const myUserId = MatrixClientPeg.get().getUserId();
    90→
    91→    // get the most recent read receipt sent by our account for the main timeline.
    92→    // N.B. this is NOT a read marker (RM, aka "read up to marker"),
    93→    // despite the name of the method :(
    94→    const readUpToId = room.getEventReadUpTo(myUserId);
    95→
    96→    // Check if the main timeline has unread messages
    97→    if (timelineHasUnread(room.timeline, readUpToId, myUserId)) {
    98→        return true;
    99→    }
   100→
   101→    // Check threads if the thread feature is enabled
   102→    if (SettingsStore.getValue("feature_thread")) {
   103→        for (const thread of room.getThreads()) {
   104→            // Get the read receipt that applies to this thread
   105→            const threadReadReceipt = thread.room.getReadReceiptForUserId(myUserId);
   106→            const threadReadUpToId = threadReadReceipt?.data.event_id ?? null;
   107→
   108→            // Check if this thread has unread messages
   109→            if (timelineHasUnread(thread.timeline, threadReadUpToId, myUserId)) {
   110→                return true;
   111→            }
   112→        }
   113→    }
   114→
   115→    return false;
   116→}
