// Check threads if the thread feature is enabled
if (SettingsStore.getValue("feature_thread")) {
    for (const thread of room.getThreads()) {
        // Get the read receipt that applies to this thread
        // Thread read receipts are stored per-thread, get the event we've read up to
        const threadReadReceipt = thread.getReadReceiptForUserId?.(myUserId);
        const threadReadUpToId = threadReadReceipt?.data.event_id ?? null;

        // Check if this thread has unread messages
        if (timelineHasUnread(thread.timeline, threadReadUpToId, myUserId)) {
            return true;
        }
    }
}

